1	package doctor
2	
3	import (
4		"fmt"
5		"io"
6		"os"
7		"runtime"
8		"sort"
9		"strings"
10	
11		"github.com/an-lee/gh-sr/internal/config"
12		"github.com/an-lee/gh-sr/internal/host"
13		"github.com/an-lee/gh-sr/internal/runner"
14	)
15	
16	const (
17		sevOK   = "OK"
18		sevWarn = "WARN"
19		sevFail = "FAIL"
20	)
21	
22	// Result aggregates doctor check outcomes for exit code decisions.
23	type Result struct {
24		Fail int
25		Warn int
26	}
27	
28	// ExitCode returns a process exit code: 1 if any FAIL, or if strict and any WARN.
29	func ExitCode(res Result, strict bool) int {
30		if res.Fail > 0 {
31			return 1
32		}
33		if strict && res.Warn > 0 {
34			return 1
35		}
36		return 0
37	}
38	
39	// Run prints diagnostics to w. cfg and cfgErr come from config.LoadFromPath (or Load) after BootstrapEnv.
40	// If cfg is nil (load error), GitHub and host checks are skipped after the configuration section.
41	func Run(w io.Writer, cfgPath, envPath string, cfg *config.Config, cfgErr error, gh *runner.GitHubClient, filterHost, filterRepo string, strict bool) Result {
42		var r Result
43	
44		fmt.Fprintln(w, "=== Local environment ===")
45	
46		if _, err := os.Stat(cfgPath); err != nil {
47			printLine(w, sevFail, "local", fmt.Sprintf("config path: %v", err))
48			r.Fail++
49		} else {
50			printLine(w, sevOK, "local", fmt.Sprintf("config file exists: %s", cfgPath))
51		}
52	
53		switch _, err := os.Stat(envPath); {
54		case os.IsNotExist(err):
55			printLine(w, sevWarn, "local", fmt.Sprintf("env file not found: %s (optional)", envPath))
56			r.Warn++
57		case err != nil:
58			printLine(w, sevWarn, "local", fmt.Sprintf("env file: %v", err))
59			r.Warn++
60		default:
61			printLine(w, sevOK, "local", fmt.Sprintf("env file present: %s", envPath))
62		}
63	
64		needSSH := cfg == nil
65		if cfg != nil {
66			for _, rc := range config.FilterRunners(cfg, filterHost, filterRepo, nil) {
67				hc := cfg.Hosts[rc.Host]
68				if !config.IsLocalAddr(hc.Addr) {
69					needSSH = true
70					break
71				}
72			}
73		}
74		if needSSH {
75			if host.HasSSHAuth() {
76				printLine(w, sevOK, "local", "SSH client auth available (agent or default ~/.ssh keys)")
77			} else {
78				printLine(w, sevWarn, "local", "no SSH agent (SSH_AUTH_SOCK) or default ~/.ssh keys; required for remote hosts")
79				r.Warn++
80			}
81		} else {
82			printLine(w, sevOK, "local", "only local hosts in scope; SSH client keys not required")
83		}
84	
85		fmt.Fprintln(w, "\n=== Configuration ===")
86		if cfgErr != nil {
87			printLine(w, sevFail, "config", cfgErr.Error())
88			r.Fail++
89			printSummary(w, r, strict)
90			return r
91		}
92		printLine(w, sevOK, "config", "YAML valid and constraints satisfied")
93	
94		runners := config.FilterRunners(cfg, filterHost, filterRepo, nil)
95		if len(runners) == 0 {
96			printLine(w, sevWarn, "config", "no runners match --host / --repo filters")
97			r.Warn++
98			printSummary(w, r, strict)
99			return r
100		}
101	
102		fmt.Fprintln(w, "\n=== GitHub API ===")
103		if gh == nil {
104			printLine(w, sevFail, "github", "skipped: no GitHub token (run `gh auth login`)")
105			r.Fail++
106		} else {
107			repos := uniqueRepos(runners)
108			for _, repo := range repos {
109				list, err := gh.ListRunners(repo)
110				if err != nil {
111					printLine(w, sevFail, "github", fmt.Sprintf("%s: %v", repo, err))
112					r.Fail++
113					continue
114				}
115				printLine(w, sevOK, "github", fmt.Sprintf("%s: list runners OK (%d registered)", repo, len(list)))
116			}
117			orgs := uniqueOrgs(runners)
118			for _, org := range orgs {
119				list, err := gh.ListRunnersScoped("org", org)
120				if err != nil {
121					printLine(w, sevFail, "github", fmt.Sprintf("org %s: %v", org, err))
122					r.Fail++
123					continue
124				}
125				printLine(w, sevOK, "github", fmt.Sprintf("org %s: list runners OK (%d registered)", org, len(list)))
126			}
127		}
128	
129		fmt.Fprintln(w, "\n=== Hosts ===")
130		hostOrder := uniqueHostNames(runners)
131		for _, hostName := range hostOrder {
132			hcfg := cfg.Hosts[hostName]
133	
134			h := host.NewHost(hostName, hcfg)
135			if err := h.Connect(); err != nil {
136				printLine(w, sevFail, hostName, fmt.Sprintf("connect: %v", err))
137				r.Fail++
138				continue
139			}
140			if err := ensureDoctorHostOS(h, hcfg.Addr); err != nil {
141				printLine(w, sevFail, hostName, fmt.Sprintf("detect os: %v", err))
142				r.Fail++
143				_ = h.Close()
144				continue
145			}
146	
147			func() {
148				defer h.Close()
149				printLine(w, sevOK, hostName, fmt.Sprintf("connected (%s)", addrSummary(hcfg.Addr)))
150				checkNative(w, hostName, h, &r)
151				checkNativeRunnerInstall(w, hostName, h, runners, &r)
152				if h.OS == "linux" {
153					checkLinuxSudo(w, hostName, h, &r)
154				}
155				if hasAgenticRunners(cfg.RunnersForHost(hostName)) {
156					checkAgenticPrereqs(w, hostName, h, &r)
157				}
158			}()
159		}
160	
161		printSummary(w, r, strict)
162		return r
163	}
164	
165	func printLine(w io.Writer, sev, scope, msg string) {
166		fmt.Fprintf(w, "%-5s [%-12s] %s\n", sev, scope, msg)
167	}
168	
169	func printSummary(w io.Writer, r Result, strict bool) {
170		fmt.Fprintln(w, "\n--- Summary ---")
171		fmt.Fprintf(w, "%d failed, %d warnings", r.Fail, r.Warn)
172		if strict {
173			fmt.Fprint(w, " (strict: warnings fail the run)")
174		}
175		fmt.Fprintln(w)
176	}
177	
178	func addrSummary(addr string) string {
179		if config.IsLocalAddr(addr) {
180			return "local"
181		}
182		return "ssh " + addr
183	}
184	
185	// ensureDoctorHostOS sets h.OS when empty: local hosts use runtime.GOOS; remote hosts use DetectOS over the existing connection.
186	func ensureDoctorHostOS(h *host.Host, addr string) error {
187		if h.OS != "" {
188			return nil
189		}
190		if config.IsLocalAddr(addr) {
191			h.OS = runtime.GOOS
192			return nil
193		}
194		detected, err := host.DetectOS(h)
195		if err != nil {
196			return err
197		}
198		h.OS = detected
199		return nil
200	}
201	
202	func uniqueRepos(runners []config.RunnerConfig) []string {
203		seen := make(map[string]struct{})
204		for _, rc := range runners {
205			if rc.Repo != "" {
206				seen[rc.Repo] = struct{}{}
207			}
208		}
209		out := make([]string, 0, len(seen))
210		for repo := range seen {
211			out = append(out, repo)
212		}
213		sort.Strings(out)
214		return out
215	}
216	
217	func uniqueOrgs(runners []config.RunnerConfig) []string {
218		seen := make(map[string]struct{})
219		for _, rc := range runners {
220			if rc.Org != "" {
221				seen[rc.Org] = struct{}{}
222			}
223		}
224		out := make([]string, 0, len(seen))
225		for org := range seen {
226			out = append(out, org)
227		}
228		sort.Strings(out)
229		return out
230	}
231	
232	func uniqueHostNames(runners []config.RunnerConfig) []string {
233		seen := make(map[string]struct{})
234		for _, rc := range runners {
235			seen[rc.Host] = struct{}{}
236		}
237		out := make([]string, 0, len(seen))
238		for name := range seen {
239			out = append(out, name)
240		}
241		sort.Strings(out)
242		return out
243	}
244	
245	// nativeInstallTargetsForHost lists (instanceName, runnerConfigName) for native-mode runners on hostName.
246	func nativeInstallTargetsForHost(runners []config.RunnerConfig, hostName string) [][2]string {
247		var out [][2]string
248		for _, rc := range runners {
249			if rc.Host != hostName {
250				continue
251			}
252			for _, inst := range rc.InstanceNames() {
253				out = append(out, [2]string{inst, rc.Name})
254			}
255		}
256		return out
257	}
258	
259	func checkNativeRunnerInstall(w io.Writer, hostName string, h *host.Host, runners []config.RunnerConfig, r *Result) {
260		for _, pair := range nativeInstallTargetsForHost(runners, hostName) {
261			inst, runnerName := pair[0], pair[1]
262			dir := h.RunnerDir(inst)
263			ok, err := runner.NativeRunnerConfigPresent(h, inst)
264			if err != nil {
265				printLine(w, sevFail, hostName, fmt.Sprintf("native: instance %s: %v", inst, err))
266				r.Fail++
267				continue
268			}
269			if !ok {
270				printLine(w, sevFail, hostName, fmt.Sprintf("native: instance %s not installed (missing .runner under %s); run: gh sr setup %s", inst, dir, runnerName))
271				r.Fail++
272				continue
273			}
274			printLine(w, sevOK, hostName, fmt.Sprintf("native: instance %s installed", inst))
275		}
276	}
277	
278	func checkNative(w io.Writer, hostName string, h *host.Host, r *Result) {
279		switch h.OS {
280		case "linux":
281			out, err := h.Run(`if command -v curl >/dev/null 2>&1 && command -v tar >/dev/null 2>&1; then echo ok; else echo missing; fi`)
282			out = strings.TrimSpace(out)
283			if err != nil || out != "ok" {
284				printLine(w, sevFail, hostName, fmt.Sprintf("native: need curl and tar on PATH (%v)", err))
285				r.Fail++
286				return
287			}
288			printLine(w, sevOK, hostName, "native: curl and tar present")
289		case "darwin":
290			out, err := h.Run(`command -v curl >/dev/null 2>&1 && echo ok || echo missing`)
291			out = strings.TrimSpace(out)
292			if err != nil || out != "ok" {
293				printLine(w, sevFail, hostName, fmt.Sprintf("native: need curl (%v)", err))
294				r.Fail++
295				return
296			}
297			printLine(w, sevOK, hostName, "native: curl present")
298		case "windows":
299			out, err := h.RunShell(`$PSVersionTable.PSVersion.ToString()`)
300			out = strings.TrimSpace(out)
301			if err != nil || out == "" {
302				printLine(w, sevFail, hostName, fmt.Sprintf("native: PowerShell check failed (%v)", err))
303				r.Fail++
304				return
305			}
306			printLine(w, sevOK, hostName, fmt.Sprintf("native: PowerShell %s", out))
307		default:
308			printLine(w, sevWarn, hostName, fmt.Sprintf("native: unknown os %q", h.OS))
309			r.Warn++
310		}
311	}
312	
313	func checkLinuxSudo(w io.Writer, hostName string, h *host.Host, r *Result) {
314		uid, err := h.Run(`id -u`)
315		if err != nil {
316			printLine(w, sevWarn, hostName, fmt.Sprintf("linux: could not check uid: %v", err))
317			r.Warn++
318			return
319		}
320		if strings.TrimSpace(uid) == "0" {
321			return
322		}
323		out, err := h.Run(`sudo -n true 2>/dev/null && echo ok || echo no`)
324		out = strings.TrimSpace(out)
325		if err != nil || out != "ok" {
326			printLine(w, sevWarn, hostName, "linux: passwordless sudo not available; gh sr setup/update may fail for package installs")
327			r.Warn++
328			return
329		}
330		printLine(w, sevOK, hostName, "linux: non-root user has passwordless sudo")
331	}
332	
333	// hasAgenticRunners returns true if any runner in the list uses the agentic profile.
334	func hasAgenticRunners(runners []config.RunnerConfig) bool {
335		for _, rc := range runners {
336			if rc.IsAgentic() {
337				return true
338			}
339		}
340		return false
341	}
342	
343	// checkAgenticPrereqs verifies Docker is available on the host for agentic workflow containers.
344	// gh-aw (GitHub Agentic Workflows) uses Docker on the host for AWF sandbox containers.
345	func checkAgenticPrereqs(w io.Writer, hostName string, h *host.Host, r *Result) {
346		if h.OS != "linux" {
347			printLine(w, sevFail, hostName, "agentic: gh-aw only supported on Linux hosts")
348			r.Fail++
349			return
350		}
351	
352		// Check docker CLI.
353		out, err := h.Run(`docker --version 2>/dev/null`)
354		if err != nil || !strings.Contains(out, "Docker version") {
355			printLine(w, sevFail, hostName, "agentic: docker CLI not found on PATH; gh-aw requires Docker to be pre-installed on the host")
356			r.Fail++
357			return
358		}
359		printLine(w, sevOK, hostName, fmt.Sprintf("agentic: docker CLI %s", strings.TrimSpace(out)))
360	
361		// Check docker daemon is running.
362		out, err = h.Run(`docker info 2>/dev/null`)
363		if err != nil {
364			printLine(w, sevFail, hostName, "agentic: docker daemon not running (docker info failed); start docker or ensure it starts at boot")
365			r.Fail++
366			return
367		}
368		printLine(w, sevOK, hostName, "agentic: docker daemon running")
369	
370		// Check docker compose plugin.
371		out, err = h.Run(`docker compose version 2>/dev/null`)
372		if err != nil {
373			printLine(w, sevWarn, hostName, "agentic: docker compose plugin not found (docker compose version failed); gh-aw may need it for multi-container setup")
374			r.Warn++
375		} else {
376			printLine(w, sevOK, hostName, fmt.Sprintf("agentic: docker compose %s", strings.TrimSpace(out)))
377		}
378	
379		// Check Docker-in-Docker: MCP gateway spawns containers via Docker socket.
380		out, err = h.Run(`docker run --rm -v /var/run/docker.sock:/var/run/docker.sock docker:cli docker ps 2>/dev/null`)
381		if err != nil {
382			printLine(w, sevFail, hostName, "agentic: cannot spawn containers via Docker socket; MCP gateway will fail to launch (see docs agentic-workflows.md §4c)")
383			r.Fail++
384		} else {
385			printLine(w, sevOK, hostName, "agentic: can spawn containers via Docker socket")
386		}
387	
388		// Check iptables is available.
389		out, err = h.Run(`command -v iptables >/dev/null 2>&1 && echo ok || echo missing`)
390		if err != nil || strings.TrimSpace(out) != "ok" {
391			printLine(w, sevFail, hostName, "agentic: iptables not found on PATH; gh-aw needs it for network egress control (DOCKER-USER chain)")
392			r.Fail++
393			return
394		}
395		printLine(w, sevOK, hostName, "agentic: iptables available")
396	
397		// Check DOCKER-USER chain exists (gh-aw creates it).
398		out, err = h.Run(`iptables -L DOCKER-USER 2>/dev/null && echo exists || echo missing`)
399		if err != nil || strings.TrimSpace(out) != "exists" {
400			printLine(w, sevWarn, hostName, "agentic: DOCKER-USER chain not found; gh-aw creates it on first run; ensure passwordless sudo for iptables")
401			r.Warn++
402		} else {
403			printLine(w, sevOK, hostName, "agentic: DOCKER-USER chain exists")
404		}
405	
406		// Check RUNNER_TEMP for agentic runners.
407		// gh-aw uses /tmp/gh-aw for its runtime tree. If the runner's RUNNER_TEMP is /tmp,
408		// bind mounts and security isolation will conflict with gh-aw's own files.
409		out, err = h.Run(`echo "${RUNNER_TEMP:-}"`)
410		if err == nil {
411			rt := strings.TrimSpace(out)
412			if rt == "/tmp" {
413				printLine(w, sevWarn, hostName, "agentic: RUNNER_TEMP=/tmp conflicts with gh-aw runtime tree at /tmp/gh-aw (mount and isolation conflicts)")
414				printLine(w, sevWarn, hostName, "agentic: fix: set RUNNER_TEMP to a path under the runner work directory, e.g. ~/.gh-sr/runners/<name>/_work/_temp")
415				r.Warn++
416			}
417		}
418	
419		// Check passwordless sudo for iptables (needed for gh-aw egress rules).
420		uid, err := h.Run(`id -u`)
421		if err != nil {
422			printLine(w, sevWarn, hostName, fmt.Sprintf("agentic: could not check uid for iptables sudo: %v", err))
423			r.Warn++
424			return
425		}
426		if strings.TrimSpace(uid) != "0" {
427			out, err = h.Run(`sudo -n iptables -L DOCKER-USER >/dev/null 2>&1 && echo ok || echo no`)
428			if err != nil || strings.TrimSpace(out) != "ok" {
429				printLine(w, sevWarn, hostName, "agentic: passwordless sudo for iptables not available; gh-aw may fail to set egress rules")
430				r.Warn++
431				return
432			}
433			printLine(w, sevOK, hostName, "agentic: passwordless sudo for iptables available")
434		}
435	
436		// Check host.docker.internal resolution inside containers.
437		// gh-aw relies on host.docker.internal to reach the MCP gateway from agent containers.
438		out, err = h.Run(`docker run --rm alpine sh -c "getent hosts host.docker.internal || echo failed" 2>/dev/null`)
439		out = strings.TrimSpace(out)
440		if err != nil || out == "failed" || out == "" {
441			printLine(w, sevFail, hostName, "agentic: host.docker.internal does not resolve inside containers; configure Docker DNS (see README)")
442			r.Fail++
443		} else if strings.Contains(out, "127.0.0.1") {
444			printLine(w, sevFail, hostName, "agentic: host.docker.internal resolves to 127.0.0.1 inside containers; this breaks gh-aw MCP gateway (see README)")
445			r.Fail++
446		} else {
447			fields := strings.Fields(out)
448			ip := ""
449			if len(fields) > 0 {
450				ip = fields[0]
451			}
452			printLine(w, sevOK, hostName, fmt.Sprintf("agentic: host.docker.internal resolves correctly inside containers (%s)", ip))
453		}
454	
455		// Check general DNS resolution inside containers.
456		// If dnsmasq is configured without upstream servers, it only answers static records
457		// and REFUSES everything else, breaking external API access (model providers, etc.).
458		out, err = h.Run(`docker run --rm alpine sh -c "nslookup github.com >/dev/null 2>&1 && echo ok || echo failed" 2>/dev/null`)
459		out = strings.TrimSpace(out)
460		if err != nil || out != "ok" {
461			printLine(w, sevFail, hostName, "agentic: external DNS (github.com) does not resolve inside containers; check Docker DNS / dnsmasq upstream server config (see README)")
462			r.Fail++
463		} else {
464			printLine(w, sevOK, hostName, "agentic: external DNS resolves inside containers")
465		}
466	
467		// Check container → host TCP reachability via host.docker.internal.
468		// The MCP gateway listens on the host; agent containers must be able to TCP-connect to it.
469		tcpCheck, err := h.Run(`docker run --rm --add-host=host.docker.internal:host-gateway alpine sh -c "(echo > /dev/tcp/host.docker.internal/80) 2>/dev/null && echo ok || echo failed" 2>/dev/null`)
470		tcpCheck = strings.TrimSpace(tcpCheck)
471		if err != nil || tcpCheck == "failed" {
472			printLine(w, sevFail, hostName, "agentic: container cannot TCP-connect to host via host.docker.internal:80; MCP gateway will be unreachable (see README §4b)")
473			r.Fail++
474		} else {
475			printLine(w, sevOK, hostName, "agentic: container can reach host via host.docker.internal:80")
476		}
477	}
