159	// windowsDeleteRunnerConfig removes the .runner file so setupNative will re-configure.
160	func windowsDeleteRunnerConfig(h *host.Host, instanceName string) string {
161		return fmt.Sprintf(
162			"%s; Remove-Item -Force (Join-Path $runnerDir '.runner') -EA SilentlyContinue; "+
163				"Remove-Item -Force (Join-Path $runnerDir '.credentials') -EA SilentlyContinue; "+
164				"Remove-Item -Force (Join-Path $runnerDir '.credentials_rsaparams') -EA SilentlyContinue",
165			windowsRunnerDirAssignment(h, "runnerDir", instanceName),
166		)
167	}
