169	func (m *Manager) setupNative(h *host.Host, rc config.RunnerConfig) error {
170		version, err := m.GitHub.GetLatestRunnerVersion()
171		if err != nil {
172			return err
173		}
174	
175		ghArch := archForGitHub(h.Arch)
176		url := runnerTarballURL(version, h.OS, ghArch)
177		if url == "" {
178			return fmt.Errorf("unsupported OS/arch: %s/%s", h.OS, h.Arch)
179		}
180	
181		for _, name := range rc.InstanceNames() {
182			dir := h.RunnerDir(name)
183	
184			installed, _ := NativeRunnerConfigPresent(h, name)
185			if installed {
186				fmt.Fprintf(m.out(), "  %s: already installed, skipping\n", name)
187				continue
188			}
189	
190			fmt.Fprintf(m.out(), "  %s: installing runner v%s...\n", name, version)
191	
192			if h.OS == "linux" {
193				installDepsCmd := linuxElevatePrelude + `
194					if ! command -v curl >/dev/null 2>&1 || ! command -v tar >/dev/null 2>&1; then
195						if command -v apt-get >/dev/null 2>&1; then $SUDO apt-get update && $SUDO apt-get install -y curl tar;
196						elif command -v yum >/dev/null 2>&1; then $SUDO yum install -y curl tar;
197						elif command -v apk >/dev/null 2>&1; then $SUDO apk add curl tar;
198						fi
199					fi
200				`
201				if _, err := h.Run(installDepsCmd); err != nil {
202					fmt.Fprintf(m.out(), "  %s: warning: failed to ensure curl/tar are installed: %v\n", name, err)
203				}
204			}
205	
206			if h.OS == "windows" {
207				fmt.Fprintf(m.out(), "  %s: downloading runner package...\n", name)
208				if _, err := h.RunShell(windowsNativeInstallScript(h, name, version, url)); err != nil {
209					return fmt.Errorf("installing runner on Windows: %w", err)
210				}
211			} else {
212				tarball := fmt.Sprintf("%s/ghsr-runner-%s-%s.tar.gz", h.TempDir(), name, version)
213				fmt.Fprintf(m.out(), "  %s: downloading runner v%s...\n", name, version)
214				if _, err := h.Run(fmt.Sprintf("mkdir -p %s", dir)); err != nil {
215					return fmt.Errorf("creating runner directory: %w", err)
216				}
217				cmds := fmt.Sprintf(
218					"cd %s && tarball=%s && rm -f \"$tarball\" && "+
219						"curl -fSL --retry 3 --retry-delay 2 -o \"$tarball\" '%s'",
220					dir, tarball, url,
221				)
222				if _, err := h.Run(cmds); err != nil {
223					return fmt.Errorf("downloading runner: %w", err)
224				}
225				fmt.Fprintf(m.out(), "  %s: extracting runner...\n", name)
226				cmds = fmt.Sprintf("cd %s && tarball=%s && tar xzf \"$tarball\" && rm -f \"$tarball\"", dir, tarball)
227				if _, err := h.Run(cmds); err != nil {
228					return fmt.Errorf("extracting runner: %w", err)
229				}
230			}
231	
232			if h.OS == "linux" {
233				fmt.Fprintf(m.out(), "  %s: installing runner dependencies...\n", name)
234				depsCmd := fmt.Sprintf(
235					"cd %s && %s && $SUDO ./bin/installdependencies.sh",
236					dir, strings.TrimSpace(linuxElevatePrelude),
237				)
238				if _, err := h.Run(depsCmd); err != nil {
239					fmt.Fprintf(m.out(), "  %s: warning: failed to install runner dependencies: %v\n", name, err)
240				}
241			}
242	
243			regToken, err := m.GitHub.GetRegistrationTokenScoped(rc.Scope(), rc.ScopeTarget())
244			if err != nil {
245				return err
246			}
247	
248			labels := strings.Join(rc.EffectiveLabels(h.OS, h.Arch), ",")
249	
250			fmt.Fprintf(m.out(), "  %s: registering runner with GitHub...\n", name)
251			if h.OS == "windows" {
252				if _, err := h.RunShell(windowsNativeConfigScript(h, rc, name, regToken)); err != nil {
253					return fmt.Errorf("configuring runner on Windows: %w", err)
254				}
255			} else {
256				configURL := nativeConfigURL(rc)
257				configCmd := fmt.Sprintf(
258					"cd %s && ./config.sh --unattended --url '%s' --token '%s' --name '%s' --labels '%s' --work '_work' --replace",
259					dir, configURL, regToken, name, labels,
260				)
261				if rc.Group != "" {
262					configCmd += fmt.Sprintf(" --runnergroup '%s'", rc.Group)
263				}
264				if rc.Ephemeral {
265					configCmd += " --ephemeral"
266				}
267				if _, err := h.Run(configCmd); err != nil {
268					return fmt.Errorf("configuring runner: %w", err)
269				}
270			}
271	
272			fmt.Fprintf(m.out(), "  %s: configured\n", name)
273		}
274	
275		// For agentic runners, install gh-aw CLI on the host.
276		// gh-aw (GitHub Agentic Workflows) uses Docker on the host for AWF sandbox containers.
277		if rc.IsAgentic() && h.OS == "linux" {
278			// Hard prerequisite check: fail fast before modifying the host.
279			if err := m.validateAgenticPrereqs(h, rc); err != nil {
280				return fmt.Errorf("agentic prerequisite check failed: %w", err)
281			}
282	
283			// Pre-flight check: warn if the runner user lacks passwordless sudo.
284			// gh-aw requires sudo to manage iptables (DOCKER-USER chain) and awf-net bridge.
285			warnAgenticSudoPrereqs(h, m.out(), rc.Name)
286	
287			// Clean up zombie Docker resources from previously crashed gh-aw jobs.
288			// If a job crashes, orphaned gh-aw containers and networks block the next job.
289			fmt.Fprintf(m.out(), "  %s: cleaning up zombie gh-aw Docker resources...\n", rc.Name)
290			cleanupOut, cleanupErr := h.Run(`
291	docker ps -a --filter "name=gh-aw" --format '{{.ID}}' 2>/dev/null | xargs -r docker rm -f 2>/dev/null
292	docker network ls --filter "name=gh-aw" --format '{{.ID}}' 2>/dev/null | xargs -r docker network rm 2>/dev/null
293	docker network prune -f 2>/dev/null
294	echo "cleanup done"
295	`)
296			if cleanupErr != nil {
297				fmt.Fprintf(m.out(), "  %s: warning: Docker cleanup failed: %v\n", rc.Name, cleanupErr)
298			} else if strings.TrimSpace(cleanupOut) != "" {
299				fmt.Fprintf(m.out(), "  %s: Docker cleanup: %s\n", rc.Name, strings.TrimSpace(cleanupOut))
300			}
301	
302			fmt.Fprintf(m.out(), "  %s: installing gh-aw CLI for agentic profile...\n", rc.Name)
303			installGHAWCmd := `if [ -d ~/.local/share/gh/extensions/gh-aw ]; then
304				echo "gh-aw already installed"
305			else
306				curl -sL https://raw.githubusercontent.com/github/gh-aw/main/install-gh-aw.sh | bash
307			fi`
308			out, err := h.Run(installGHAWCmd)
309			if err != nil {
310				fmt.Fprintf(m.out(), "  %s: warning: failed to install gh-aw CLI: %v\n", rc.Name, err)
311			} else {
312				fmt.Fprintf(m.out(), "  %s: gh-aw CLI installed\n", rc.Name)
313				if out != "" {
314					fmt.Fprintf(m.out(), "  %s: gh-aw: %s\n", rc.Name, strings.TrimSpace(out))
315				}
316			}
317	
318			// Set up /opt/hostedtoolcache for gh-aw agent containers.
319			// gh-aw searches for tools (e.g., claude) in /opt/hostedtoolcache, which exists on
320			// GitHub Hosted Runners but not on self-hosted runners. We create a bind mount so
321			// agent containers can find npm-installed tools.
322			fmt.Fprintf(m.out(), "  %s: setting up /opt/hostedtoolcache for agentic workflows...\n", rc.Name)
323			npmPrefixCmd := `npm config get prefix 2>/dev/null || echo "/usr/local"`
324			npmPrefix, err := h.Run(npmPrefixCmd)
325			if err != nil {
326				fmt.Fprintf(m.out(), "  %s: warning: failed to detect npm prefix: %v\n", rc.Name, err)
327			} else {
328				npmPrefix = strings.TrimSpace(npmPrefix)
329				hostedtoolcacheSetup := fmt.Sprintf(`%s
330				if [ -d /opt/hostedtoolcache ]; then
331					if [ -L /opt/hostedtoolcache ]; then
332						if [ "$(readlink -f /opt/hostedtoolcache)" != "%s" ]; then
333							echo "Updating /opt/hostedtoolcache symlink to %s"
334							$SUDO rm -f /opt/hostedtoolcache
335							$SUDO mkdir -p /opt/hostedtoolcache
336							$SUDO mount --bind %s /opt/hostedtoolcache
337						else
338							echo "/opt/hostedtoolcache already correctly configured"
339						fi
340					else
341						echo "/opt/hostedtoolcache already exists as a directory"
342					fi
343				else
344					echo "Creating /opt/hostedtoolcache -> %s"
345					$SUDO mkdir -p /opt/hostedtoolcache
346					$SUDO mount --bind %s /opt/hostedtoolcache
347					if ! grep -q "^%s" /etc/fstab 2>/dev/null; then
348						echo "%s /opt/hostedtoolcache none defaults,bind 0 0" | $SUDO tee -a /etc/fstab
349					fi
350				fi`, linuxElevatePrelude, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix)
351				out, err := h.Run(hostedtoolcacheSetup)
352				if err != nil {
353					fmt.Fprintf(m.out(), "  %s: warning: failed to set up /opt/hostedtoolcache: %v\n", rc.Name, err)
354				} else {
355					fmt.Fprintf(m.out(), "  %s: /opt/hostedtoolcache configured\n", rc.Name)
356					if out != "" {
357						fmt.Fprintf(m.out(), "  %s: hostedtoolcache: %s\n", rc.Name, strings.TrimSpace(out))
358					}
359				}
360			}
361	
362			// Set up Docker DNS for agentic workflows.
363			// Agent containers (gh-aw) use host.docker.internal to reach the MCP Gateway running
364			// on the host network. Linux Docker does not resolve this by default; we configure
365			// dnsmasq as a local DNS resolver that answers host.docker.internal from the docker0
366			// bridge IP and forwards everything else upstream. This also ensures external DNS
367			// (model provider APIs, GitHub, etc.) works from inside agent containers.
368			fmt.Fprintf(m.out(), "  %s: setting up Docker DNS for agentic workflows...\n", rc.Name)
369			if err := m.setupAgenticDNSConfigure(h, rc.Name); err != nil {
370				fmt.Fprintf(m.out(), "  %s: warning: Docker DNS setup failed: %v\n", rc.Name, err)
371			}
372	
373			// Pre-pull critical gh-aw images to reduce first-job startup latency.
374			// These images are required by every agentic workflow run and can be several hundred MB.
375			fmt.Fprintf(m.out(), "  %s: pre-pulling gh-aw images (this may take a few minutes)...\n", rc.Name)
376			for _, img := range []string{
377				"ghcr.io/github/gh-aw-firewall/agent:latest",
378				"ghcr.io/github/gh-aw-mcpg:latest",
379			} {
380				pullOut, pullErr := h.Run(fmt.Sprintf("docker pull %s 2>&1", img))
381				pullOut = strings.TrimSpace(pullOut)
382				if pullErr != nil {
383					fmt.Fprintf(m.out(), "  %s: warning: failed to pull %s: %v\n", rc.Name, img, pullErr)
384					if pullOut != "" {
385						fmt.Fprintf(m.out(), "  %s:   %s\n", rc.Name, pullOut)
386					}
387				} else {
388					// Show the final status line (e.g. "Status: Image is up to date for ...")
389					lines := strings.Split(pullOut, "\n")
390					statusLine := pullOut
391					for i := len(lines) - 1; i >= 0; i-- {
392						if l := strings.TrimSpace(lines[i]); l != "" {
393							statusLine = l
394							break
395						}
396					}
397					fmt.Fprintf(m.out(), "  %s: pulled %s: %s\n", rc.Name, img, statusLine)
398				}
399			}
400		}
401	
402		return nil
403	}
404	
405	func (m *Manager) startNative(h *host.Host, rc config.RunnerConfig, instanceName string) error {
406		return m.startNativeOnce(h, rc, instanceName, true)
407	}
408	
409	// startNativeOnce starts the runner and optionally detects a stale registration.
410	// When retryOnStale is true and the runner exits immediately with the stale-registration
411	// message, it clears local credentials, re-runs setupNative, and retries once.
412	func (m *Manager) startNativeOnce(h *host.Host, rc config.RunnerConfig, instanceName string, retryOnStale bool) error {
413		dir := h.RunnerDir(instanceName)
414	
415		ok, err := NativeRunnerConfigPresent(h, instanceName)
416		if err != nil {
417			return fmt.Errorf("checking runner install at %s: %w", dir, err)
418		}
419		if !ok {
420			fmt.Fprintf(m.out(), "  %s: not installed, running setup (this takes a few minutes)...\n", instanceName)
421			if setupErr := m.setupNative(h, rc); setupErr != nil {
422				return fmt.Errorf("auto-setup for %s: %w", instanceName, setupErr)
423			}
424		}
425	
426		if h.OS == "windows" {
427			out, err := h.RunShell(windowsNativeStartScript(h, instanceName))
428			if err != nil {
429				return err
430			}
431			fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
432	
433			if retryOnStale {
434				fmt.Fprintf(m.out(), "  %s: waiting for runner to initialize...\n", instanceName)
435				checkOut, _ := h.RunShell(windowsCheckStaleRegistration(h, instanceName))
436				if strings.TrimSpace(checkOut) == "stale" {
437					return m.handleStaleRegistration(h, rc, instanceName)
438				}
439			}
440			return nil
441		}
442	
443		// Unix (Linux / macOS)
444		cmd := fmt.Sprintf(
445			`cd %s; pid_file=".runner_pid"; `+
446				`if [ -f "$pid_file" ] && kill -0 "$(cat "$pid_file")" 2>/dev/null; then echo "already running"; exit 0; fi; `+
447				`nohup ./run.sh > runner.log 2>&1 & { echo $!; } > "$pid_file"; echo "started PID $!"`,
448			dir,
449		)
450		out, err := h.Run(cmd)
451		if err != nil {
452			return err
453		}
454		fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
455	
456		if retryOnStale {
457			fmt.Fprintf(m.out(), "  %s: waiting for runner to initialize...\n", instanceName)
458			checkCmd := fmt.Sprintf(
459				`sleep 5 && cd %s && pid=$(cat .runner_pid 2>/dev/null) && `+
460					`if [ -n "$pid" ] && kill -0 "$pid" 2>/dev/null; then echo ok; `+
461					`elif grep -q %q runner.log 2>/dev/null; then echo stale; `+
462					`else echo ok; fi`,
463				dir, staleRegistrationMsg,
464			)
465			checkOut, _ := h.Run(checkCmd)
466			if strings.TrimSpace(checkOut) == "stale" {
467				return m.handleStaleRegistration(h, rc, instanceName)
468			}
469		}
470		return nil
471	}
472	
473	func (m *Manager) handleStaleRegistration(h *host.Host, rc config.RunnerConfig, instanceName string) error {
474		fmt.Fprintf(m.out(), "  %s: registration expired on GitHub, re-configuring...\n", instanceName)
475		dir := h.RunnerDir(instanceName)
476	
477		if h.OS == "windows" {
478			h.RunShell(windowsDeleteRunnerConfig(h, instanceName))
479		} else {
480			h.Run(fmt.Sprintf("rm -f %s/.runner %s/.credentials %s/.credentials_rsaparams", dir, dir, dir))
481		}
482	
483		if err := m.setupNative(h, rc); err != nil {
484			return fmt.Errorf("re-configuring after stale registration: %w", err)
485		}
486	
487		return m.startNativeOnce(h, rc, instanceName, false)
488	}
489	
490	func (m *Manager) stopNative(h *host.Host, instanceName string) error {
491		dir := h.RunnerDir(instanceName)
492	
493		if h.OS == "windows" {
494			cmd := fmt.Sprintf(
495				"%s; $pidFile = Join-Path $runnerDir '.runner_pid'; "+
496					"if (-not (Test-Path $pidFile)) { Write-Host 'not running'; exit 0 }; "+
497					"$p = (Get-Content $pidFile | Select-Object -First 1).Trim(); "+
498					"$null = & taskkill.exe /PID $p /T /F 2>&1; "+
499					"if ($LASTEXITCODE -eq 0) { Write-Host 'stopped' } else { Write-Host 'not running' }; "+
500					"Remove-Item $pidFile -Force -EA SilentlyContinue",
501				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
502			)
503			out, err := h.RunShell(cmd)
504			if err != nil {
505				return err
506			}
507			fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
508			return nil
509		}
510	
511		cmd := fmt.Sprintf(
512			`cd %s && pid_file=".runner_pid" && `+
513				`if [ ! -f "$pid_file" ]; then echo "not running"; exit 0; fi && `+
514				`pid=$(cat "$pid_file") && `+
515				`if ! kill -0 "$pid" 2>/dev/null; then echo "not running"; rm -f "$pid_file"; exit 0; fi && `+
516				`kill "$pid" && `+
517				`for i in $(seq 1 10); do kill -0 "$pid" 2>/dev/null || break; sleep 1; done && `+
518				`kill -0 "$pid" 2>/dev/null && kill -9 "$pid" 2>/dev/null; `+
519				`rm -f "$pid_file" && echo "stopped"`,
520			dir,
521		)
522		out, err := h.Run(cmd)
523		if err != nil {
524			return err
525		}
526		fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
527		return nil
528	}
529	
530	func (m *Manager) removeNative(h *host.Host, rc config.RunnerConfig, instanceName string) error {
531		dir := h.RunnerDir(instanceName)
532	
533		_ = m.stopNative(h, instanceName)
534	
535		removeToken, err := m.GitHub.GetRemovalTokenScoped(rc.Scope(), rc.ScopeTarget())
536		if err != nil {
537			fmt.Fprintf(m.out(), "  %s: warning: could not get removal token: %v\n", instanceName, err)
538		} else {
539			if h.OS == "windows" {
540				cmd := fmt.Sprintf(
541					"%s; Set-Location -Path $runnerDir; & .\\config.cmd remove --token %s",
542					windowsRunnerDirAssignment(h, "runnerDir", instanceName),
543					powerShellSingleQuoted(removeToken),
544				)
545				h.RunShell(cmd)
546			} else {
547				cmd := fmt.Sprintf("cd %s && ./config.sh remove --token '%s'", dir, removeToken)
548				h.Run(cmd)
549			}
550			fmt.Fprintf(m.out(), "  %s: deregistered\n", instanceName)
551		}
552	
553		if h.OS == "windows" {
554			h.RunShell(fmt.Sprintf("%s; Remove-Item -Recurse -Force $runnerDir", windowsRunnerDirAssignment(h, "runnerDir", instanceName)))
555		} else {
556			h.Run(fmt.Sprintf("rm -rf %s", dir))
557		}
558	
559		fmt.Fprintf(m.out(), "  %s: removed\n", instanceName)
560		return nil
561	}
562	
563	func (m *Manager) statusNative(h *host.Host, instanceName string) string {
564		dir := h.RunnerDir(instanceName)
565	
566		if kind, err := autostart.Detect(h, instanceName); err == nil && kind != autostart.KindNone {
567			active, err := autostart.IsServiceActive(h, instanceName, kind)
568			if err != nil {
569				return "unknown"
570			}
571			if active {
572				return "running"
573			}
574			return "stopped"
575		}
576	
577		if h.OS == "windows" {
578			cmd := fmt.Sprintf(
579				"%s; if (-not (Test-Path (Join-Path $runnerDir '.runner'))) { Write-Host 'not installed'; exit 0 }; "+
580					"$pidFile = Join-Path $runnerDir '.runner_pid'; "+
581					"if (-not (Test-Path $pidFile)) { Write-Host 'stopped'; exit 0 }; "+
582					"$p = Get-Content $pidFile; "+
583					"try { Get-Process -Id $p -EA Stop | Out-Null; Write-Host 'running' } catch { Write-Host 'stopped' }",
584				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
585			)
586			out, _ := h.RunShell(cmd)
587			return strings.TrimSpace(out)
588		}
589	
590		cmd := fmt.Sprintf(
591			`d="%s" && `+
592				`if [ ! -f "$d/.runner" ]; then echo "not installed"; exit 0; fi && `+
593				`pid_file="$d/.runner_pid" && `+
594				`if [ ! -f "$pid_file" ]; then echo "stopped"; exit 0; fi && `+
595				`pid=$(cat "$pid_file") && `+
596				`if kill -0 "$pid" 2>/dev/null; then echo "running"; else echo "stopped"; fi`,
597			dir,
598		)
599		out, err := h.Run(cmd)
600		if err != nil {
601			return "unknown"
602		}
603		return strings.TrimSpace(out)
604	}
605	
606	func (m *Manager) logsNative(h *host.Host, instanceName string) (string, error) {
607		dir := h.RunnerDir(instanceName)
608	
609		if h.OS == "windows" {
610			cmd := fmt.Sprintf(
611				"%s; $logFile = Join-Path $runnerDir 'runner.log'; "+
612					"$diagDir = Join-Path $runnerDir '_diag'; "+
613					"$tailMain = { if (Test-Path $logFile) { $lines = @(Get-Content -LiteralPath $logFile -Tail 50 -EA SilentlyContinue); "+
614					"$j = [string]::Join([Environment]::NewLine, $lines); "+
615					"if ($lines.Count -gt 0 -and ($j -match '\\S')) { $j } else { $null } } else { $null } }; "+
616					"$main = & $tailMain; "+
617					"if ($null -ne $main) { Write-Output $main } "+
618					"elseif (Test-Path $diagDir) { "+
619					"$latest = Get-ChildItem -Path $diagDir -Filter *.log -File -EA SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 1; "+
620					"if ($latest) { Write-Output ('--- _diag/' + $latest.Name + ' (last 50 lines) ---'); Get-Content -LiteralPath $latest.FullName -Tail 50 } "+
621					"else { Write-Output 'no logs found' } } "+
622					"else { Write-Output 'no logs found' }",
623				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
624			)
625			return h.RunShell(cmd)
626		}
627	
628		cmd := fmt.Sprintf("tail -50 %s/runner.log 2>/dev/null || echo 'no logs found'", dir)
629		return h.Run(cmd)
630	}
