9		"gopkg.in/yaml.v3"
10	)
11	
12	const LocalAddr = "local"
13	
14	func IsLocalAddr(addr string) bool {
15		return strings.EqualFold(strings.TrimSpace(addr), LocalAddr)
16	}
17	
18	type Config struct {
19		GitHub  GitHubConfig          `yaml:"github"`
20		Hosts   map[string]HostConfig `yaml:"hosts"`
21		Runners []RunnerConfig        `yaml:"runners"`
22	}
23	
24	type GitHubConfig struct {
25		PAT string `yaml:"pat"`
26	}
27	
28	type HostConfig struct {
29		Addr      string `yaml:"addr"`
30		OS        string `yaml:"os"`
31		Arch      string `yaml:"arch"`
32		WindowsPS string `yaml:"windows_ps"` // powershell (default) or pwsh — which exe runs encoded remote scripts on Windows
33	}
