35	type RunnerConfig struct {
36		Name      string   `yaml:"name"`
37		Repo      string   `yaml:"repo"`
38		Org       string   `yaml:"org"`
39		Group     string   `yaml:"group"`
40		Host      string   `yaml:"host"`
41		Count     int      `yaml:"count"`
42		Labels    []string `yaml:"labels"`
43		Ephemeral bool     `yaml:"ephemeral"`
44		Profile   string   `yaml:"profile"` // "agentic" for GitHub Agentic Workflows
45	}
46	
47	// IsAgentic returns true if the runner uses the agentic profile.
48	func (rc *RunnerConfig) IsAgentic() bool {
49		return rc.Profile == "agentic"
50	}
51	
52	// Scope returns "repo" or "org" depending on how the runner is registered.
53	func (rc *RunnerConfig) Scope() string {
54		if rc.Org != "" {
55			return "org"
56		}
57		return "repo"
58	}
59	
60	// ScopeTarget returns the repo (owner/repo) or org name used for GitHub API calls.
61	func (rc *RunnerConfig) ScopeTarget() string {
62		if rc.Org != "" {
63			return rc.Org
64		}
65		return rc.Repo
66	}
67	
68	// EffectiveMode always returns "native" (docker mode has been removed).
69	func (rc *RunnerConfig) EffectiveMode(_ string) string {
70		return "native"
71	}
72	
73	// DefaultLabels generates standard GitHub Actions labels based on host OS and arch.
74	func DefaultLabels(hostOS, arch string) []string {
75		labels := []string{"self-hosted"}
76	
77		osLabel := ""
78		switch hostOS {
79		case "linux":
80			osLabel = "Linux"
81		case "darwin":
82			osLabel = "macOS"
83		case "windows":
84			osLabel = "Windows"
85		}
86		if osLabel != "" {
87			labels = append(labels, osLabel)
88		}
89	
90		archLabel := ""
91		switch arch {
92		case "amd64":
93			archLabel = "X64"
94		case "arm64":
95			archLabel = "ARM64"
96		}
97		if archLabel != "" {
98			labels = append(labels, archLabel)
99		}
100	
101		return labels
102	}
103	
104	// EffectiveLabels returns the runner's labels, auto-generating them from host info if empty.
105	// For agentic profile runners, "agentic" label is always appended.
106	func (rc *RunnerConfig) EffectiveLabels(hostOS, arch string) []string {
107		var labels []string
108		if len(rc.Labels) > 0 {
109			labels = rc.Labels
110		} else {
111			labels = DefaultLabels(hostOS, arch)
112		}
113		if rc.IsAgentic() && !hasLabel(labels, "agentic") {
114			labels = append(labels, "agentic")
115		}
116		return labels
117	}
118	
119	func hasLabel(labels []string, target string) bool {
120		for _, l := range labels {
121			if strings.EqualFold(l, target) {
122				return true
123			}
124		}
125		return false
126	}
127	
128	func (rc *RunnerConfig) InstanceNames() []string {
129		count := rc.Count
130		if count < 1 {
131			count = 1
132		}
133		names := make([]string, count)
134		for i := range count {
135			names[i] = fmt.Sprintf("%s-%d", rc.Name, i+1)
136		}
137		return names
138	}
