140	func Load(path string) (*Config, error) {
141		data, err := os.ReadFile(path)
142		if err != nil {
143			return nil, fmt.Errorf("reading config: %w", err)
144		}
145	
146		var cfg Config
147		if err := yaml.Unmarshal(data, &cfg); err != nil {
148			return nil, fmt.Errorf("parsing config: %w", err)
149		}
150	
151		cfg.resolveEnvRefs()
152		cfg.applyDefaults()
153	
154		if err := cfg.Validate(); err != nil {
155			return nil, err
156		}
157	
158		return &cfg, nil
159	}
160	
161	func (c *Config) resolveEnvRefs() {
162		c.GitHub.PAT = resolveEnv(c.GitHub.PAT)
163	}
164	
165	func resolveEnv(val string) string {
166		if strings.HasPrefix(val, "env:") {
167			envVar := strings.TrimPrefix(val, "env:")
168			return os.Getenv(envVar)
169		}
170		return val
171	}
172	
173	func normalizeArch(goarch string) string {
174		switch goarch {
175		case "amd64", "arm64":
176			return goarch
177		default:
178			return goarch
179		}
180	}
181	
182	func (c *Config) applyDefaults() {
183		for name, h := range c.Hosts {
184			if IsLocalAddr(h.Addr) {
185				if h.OS == "" {
186					h.OS = runtime.GOOS
187				}
188				if h.Arch == "" {
189					h.Arch = normalizeArch(runtime.GOARCH)
190				}
191				c.Hosts[name] = h
192			}
193		}
194		for i := range c.Runners {
195			if c.Runners[i].Count < 1 {
196				c.Runners[i].Count = 1
197			}
198			c.Runners[i].applyAgenticDefaults()
199		}
200	}
201	
202	func (rc *RunnerConfig) applyAgenticDefaults() {
203		if !rc.IsAgentic() {
204			return
205		}
206		// Agentic runners get "agentic" label auto-added if not present.
207		if !hasLabel(rc.Labels, "agentic") {
208			rc.Labels = append(rc.Labels, "agentic")
209		}
210	}
211	
212	func (c *Config) Validate() error {
213		if c.GitHub.PAT != "" {
214			return fmt.Errorf("github.pat is no longer supported; remove it from runners.yml and authenticate with `gh auth login`")
215		}
216	
217		if len(c.Hosts) == 0 {
218			return fmt.Errorf("at least one host must be defined")
219		}
220	
221		for name, h := range c.Hosts {
222			if h.Addr == "" {
223				return fmt.Errorf("host %q: addr is required (use \"local\" for the current machine)", name)
224			}
225			// os and arch may be empty for remote hosts -- they are auto-detected over SSH before operations.
226			if h.OS != "" {
227				switch h.OS {
228				case "linux", "darwin", "windows":
229				default:
230					return fmt.Errorf("host %q: os must be linux, darwin, or windows (got %q)", name, h.OS)
231				}
232			}
233			if h.Arch != "" {
234				switch h.Arch {
235				case "amd64", "arm64":
236				default:
237					return fmt.Errorf("host %q: arch must be amd64 or arm64 (got %q)", name, h.Arch)
238				}
239			}
240			if h.WindowsPS != "" {
241				if h.OS != "" && h.OS != "windows" {
242					return fmt.Errorf("host %q: windows_ps is only valid when os is windows", name)
243				}
244				switch strings.ToLower(strings.TrimSpace(h.WindowsPS)) {
245				case "powershell", "pwsh":
246				default:
247					return fmt.Errorf("host %q: windows_ps must be powershell or pwsh (got %q)", name, h.WindowsPS)
248				}
249			}
250		}
251	
252		if len(c.Runners) == 0 {
253			return fmt.Errorf("at least one runner must be defined")
254		}
255	
256		for _, r := range c.Runners {
257			if r.Name == "" {
258				return fmt.Errorf("runner name is required")
259			}
260			if r.Repo == "" && r.Org == "" {
261				return fmt.Errorf("runner %q: repo or org is required", r.Name)
262			}
263			if r.Repo != "" && r.Org != "" {
264				return fmt.Errorf("runner %q: specify repo or org, not both", r.Name)
265			}
266			if r.Group != "" && r.Org == "" {
267				return fmt.Errorf("runner %q: group requires org (runner groups are organization-level)", r.Name)
268			}
269			if r.Host == "" {
270				return fmt.Errorf("runner %q: host is required", r.Name)
271			}
272			if _, ok := c.Hosts[r.Host]; !ok {
273				return fmt.Errorf("runner %q: host %q not found in hosts", r.Name, r.Host)
274			}
275			if r.Profile != "" && r.Profile != "agentic" {
276				return fmt.Errorf("runner %q: profile must be empty or \"agentic\" (got %q)", r.Name, r.Profile)
277			}
278		}
279	
280		return nil
281	}
282	
283	// NeedsDetection reports whether any host is missing os or arch (and is not local).
284	func (c *Config) NeedsDetection() bool {
285		for _, h := range c.Hosts {
286			if !IsLocalAddr(h.Addr) && (h.OS == "" || h.Arch == "") {
287				return true
288			}
289		}
290		return false
291	}
292	
293	func (c *Config) RunnersForHost(hostName string) []RunnerConfig {
294		var result []RunnerConfig
295		for _, r := range c.Runners {
296			if r.Host == hostName {
297				result = append(result, r)
298			}
299		}
300		return result
301	}
302	
303	func (c *Config) RunnersForRepo(repo string) []RunnerConfig {
304		var result []RunnerConfig
