73	// encodePowerShellScript returns the base64 payload required by powershell.exe / pwsh -EncodedCommand (UTF-16LE).
74	func encodePowerShellScript(script string) string {
75		u16 := utf16.Encode([]rune(script))
76		b := make([]byte, len(u16)*2)
77		for i, v := range u16 {
78			b[i*2] = byte(v)
79			b[i*2+1] = byte(v >> 8)
