147		if h.OS == "windows" {
148			return `\`
149		}
150		return "/"
151	}
152	
153	// SSHUser returns the SSH login from Addr when it uses user@host form; otherwise "" (e.g. local, bare hostname).
154	func (h *Host) SSHUser() string {
155		if IsLocal(h.Addr) {
156			return ""
157		}
158		u, _ := parseAddr(h.Addr)
159		return u
