				os.Exit(code)
			}
			return nil
		},
	}
	cmd.Flags().BoolVar(&strict, "strict", false, "non-zero exit if any check is WARN (default: only FAIL fails the run)")
	cmd.Flags().BoolVar(&fix, "fix", false, "automatically attempt to fix failures by re-running setup")
